function getLanesLexiconUrl(rootConsonants) {
  // rootConsonants: Array von arabischen Buchstaben, z.B. ['ك', 'ت', 'ب']
  // Gibt die URL zu Lane's Lexicon auf ejtaal.net zurueck
  const translitMap = {
    'ا': 'A', 'ب': 'b', 'ت': 't', 'ث': 'v', 'ج': 'j',
    'ح': 'H', 'خ': 'x', 'د': 'd', 'ذ': '*', 'ر': 'r',
    'ز': 'z', 'س': 's', 'ش': '$', 'ص': 'S', 'ض': 'D',
    'ط': 'T', 'ظ': 'Z', 'ع': 'E', 'غ': 'g', 'ف': 'f',
    'ق': 'q', 'ك': 'k', 'ل': 'l', 'م': 'm', 'ن': 'n',
    'ه': 'h', 'و': 'w', 'ي': 'y'
  };
  const translitRoot = rootConsonants.map(c => translitMap[c] || c).join('');
  // #ll= selects Lane's Lexicon within Arabic Almanac
  return `https://ejtaal.net/aa/#ll=${translitRoot}`;
}

function getCorpusDictUrl(rootConsonants) {
  // Corpus Quran Dictionary — NOT Lane's Lexicon
  const translitMap = { /* same map */ };
  const translitRoot = rootConsonants.map(c => translitMap[c] || c).join('');
  return `https://corpus.quran.com/qurandictionary.jsp?q=${translitRoot}`;
}
